#include <torch/extension.h>
#include <c10/cuda/CUDAStream.h>
#include <cuda_runtime.h>
#include <cmath>

// Problem 016 — RoPE inverse-frequency initialization.
//
//   inv_freq[i] = 1 / rope_theta^(2*i / head_dim)
//               = rope_theta^(-i / 64)                 for i in [0, 64)
//               = exp2( i * c ),   c = -log2(rope_theta) / 64
//
// This op is pure launch/latency-bound: a 256-byte, write-only, 64-element
// output.  The 0.570 champion (1 block / 64 threads, scalar exp2f per thread,
// current-stream launch) already sits near the single-launch floor.  The
// residual gap to the ~0.40us SOL is torch::empty + pybind marshalling +
// launch latency — none of which a kernel-body change can touch.
//
// Lever pulled here (vectorized float4 stores — the untried reserve play):
//  - 16 threads instead of 64, each writing 4 contiguous floats via a single
//    128-bit float4 store (STG.E.128).  16 vectorized writes replace 64 scalar
//    writes, and the branch guard is eliminated (16*4 == 64 exactly).
//  - The 4 exp2f calls per thread are back-to-back; with only 16 threads
//    (half a warp), there is no sibling-warp to hide the ~8-cycle exp2f
//    latency.  However, the kernel body is already ~ns against a ~1us launch
//    floor, so this latency exposure is invisible in the end-to-end.
//
// Accuracy: theta > 1 => inv_freq in (0, 1], so the worst-case absolute error
// equals the ~2.7e-6 relative error (log2-rounding into fp32 + exp2f ~1ulp).
// That is < 1e-5 atol for every element (>=3x margin), value-independent.

constexpr int HEAD_DIM = 128;
constexpr int N = HEAD_DIM / 2;  // 64

__global__ void __launch_bounds__(16)
rope_inv_freq_kernel(float* __restrict__ out, float c)
{
    const int base = threadIdx.x * 4;
    float4 v;
    v.x = exp2f(static_cast<float>(base)     * c);
    v.y = exp2f(static_cast<float>(base + 1) * c);
    v.z = exp2f(static_cast<float>(base + 2) * c);
    v.w = exp2f(static_cast<float>(base + 3) * c);
    reinterpret_cast<float4*>(out)[threadIdx.x] = v;
}

// Entry point called by the harness.
torch::Tensor run(float rope_theta)
{
    auto out = torch::empty(
        {N},
        torch::TensorOptions()
            .dtype(torch::kFloat32)
            .device(torch::kCUDA));

    // Scale factor computed once on the host (no GPU work): correctly-rounded
    // fp32 value of -log2(theta)/64.  /64 is exact (power of two).
    const double L = std::log2(static_cast<double>(rope_theta));
    const float  c = static_cast<float>(-L / static_cast<double>(N));

    // Issue on torch's current stream (not the legacy default stream) to avoid
    // the NULL-stream implicit synchronization barrier on the timed path.
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    rope_inv_freq_kernel<<<1, 16, 0, stream>>>(out.data_ptr<float>(), c);
    return out;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m)
{
    m.def("run", &run, "RoPE inverse frequency (float scalar -> (64,) fp32)");
}

